// ONE-TIME dev script: regenerates src/starfield-data.ts from the sibling
// star-catalog-web repo's bundled HYG snapshot. The generated file is COMMITTED;
// CI never runs this and never reads the sibling repo.
//
//   node scripts/generate-starfield.mjs [path/to/stars.json]
//
// stars.json is sorted brightest-first; we keep the first 150 entries with
// {ra, dec, mag, ci, proper?} rounded to 2 decimals (~4 KB of TypeScript).
import { readFileSync, writeFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const here = dirname(fileURLToPath(import.meta.url));
const src =
  process.argv[2] ??
  join(here, "..", "..", "star-catalog-web", "public", "data", "stars.json");
const out = join(here, "..", "src", "starfield-data.ts");

const COUNT = 150;
const r2 = (n) => Math.round(n * 100) / 100;

const all = JSON.parse(readFileSync(src, "utf8"));
const stars = all.slice(0, COUNT).map((s) => {
  const star = { ra: r2(s.ra), dec: r2(s.dec), mag: r2(s.mag), ci: r2(s.ci ?? 0) };
  if (s.proper) star.proper = s.proper;
  return star;
});

const lines = stars
  .map((s) => {
    const proper = s.proper ? `, proper: ${JSON.stringify(s.proper)}` : "";
    return `  { ra: ${s.ra}, dec: ${s.dec}, mag: ${s.mag}, ci: ${s.ci}${proper} },`;
  })
  .join("\n");

writeFileSync(
  out,
  `// GENERATED by scripts/generate-starfield.mjs — do not edit by hand.
// The ${COUNT} brightest stars of the 8,920-star naked-eye HYG snapshot bundled
// with star-catalog-web (HYG database, Astronomy Nexus, CC BY-SA).
export interface FieldStar {
  ra: number;
  dec: number;
  mag: number;
  ci: number;
  proper?: string;
}

export const FIELD_STARS: FieldStar[] = [
${lines}
];
`,
);
console.log(`wrote ${out} (${stars.length} stars from ${src})`);
